    return not stack

class MinStack:
    def __init__(self):
        self.stack = []
        self.min_stack = []
    def push(self, val):
        self.stack.append(val)
        min_val = min(val, self.min_stack[-1] if self.min_stack else val)
        self.min_stack.append(min_val)
    def pop(self):
        self.stack.pop()
        self.min_stack.pop()
    def top(self):
        return self.stack[-1]
    def getMin(self):
        return self.min_stack[-1]

def evalRPN(tokens):
    stack = []
    ops = {'+', '-', '*', '/'}
    for t in tokens:
        if t in ops:
            b, a = stack.pop(), stack.pop()
            if t == '+':
                stack.append(a + b)
            elif t == '-':
                stack.append(a - b)
            elif t == '*':
                stack.append(a * b)
            else:
                stack.append(int(a / b))
        else:
            stack.append(int(t))
    return stack[0]

def generateParenthesis(n):
    res = []
    def backtrack(open, close, curr):
        if len(curr) == 2 * n:
            res.append(curr)
            return
        if open < n:
            backtrack(open + 1, close, curr + '(')
        if close < open:
            backtrack(open, close + 1, curr + ')')
    backtrack(0, 0, '')
    return res

def dailyTemperatures(temps):
    res = [0] * len(temps)
